function hrefFor(type, value, profileUrl) {
  if (profileUrl) return profileUrl
  switch (type) {
    case 'email': return `mailto:${value}`
    case 'phone': return `tel:${value}`
    case 'linkedin': return value.startsWith('http') ? value : `https://linkedin.com/in/${value}`
    case 'twitter': return `https://x.com/${value}`
    default: return null
  }
}

const effectiveType = computed(() => {
  if (props.type === 'email' && ['whmcs', 'metricscube'].includes(props.sysType)) {
    return props.sysType
  }
  return props.type
})

const icon = computed(() => ICONS[effectiveType.value] || ICONS.email)

const iconTitle = computed(() => {
  let label = icon.value.title
  if (props.sysSlug && props.sysSlug !== 'default') {
    label += ` (${props.sysSlug})`
  }
  return label
})

const href = computed(() => hrefFor(props.type, props.value, props.sysType === 'whmcs' ? props.profileUrl : null))
